def extract_perf(resultfile, perf):
    # pattern_str = r'\s*' + re.escape(perf) + r'\s*=\s*(-?\d+(?:\.\d+)?(?:e[+-]?\d+)?|\w+)'
    # 修改正则：支持 -inf, inf, NaN 以及科学计数法。直接匹配等号后面的所有非空白字符是最稳妥的
    pattern_str = r'\s*' + re.escape(perf) + r'\s*=\s*([^\s]+)'
    pattern = re.compile(pattern_str, re.IGNORECASE)
    if not os.path.exists(resultfile):
        print("result file not exist")
        return 'NaN'
    try:
        with open(resultfile, 'r', encoding='iso-8859-1') as f:
            for line in f:
                if (match := pattern.search(line)):
                    return match.group(1)
        print("file exist but not match")
        return 'NaN'  # 文件存在但未找到匹配时返回 'NaN'
    except Exception as e:
        print("else error")
        return 'NaN'
